import React, { useState } from "react";
import "./Calendar.css";

const WEEK_DAYS = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];

const EVENTS = [
  { date: "2025-12-05", type: "birthday", label: "Friend Birthday" },
  { date: "2025-12-10", type: "leave", label: "Casual Leave" },
  { date: "2025-12-25", type: "holiday", label: "Christmas" },
];

export default function Calendar() {
  const [currentDate, setCurrentDate] = useState(new Date(2025, 11, 1));
  const [view, setView] = useState("month");

  const [filters, setFilters] = useState({
    holiday: true,
    leave: true,
    birthday: true,
  });

  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();

  const firstDay = new Date(year, month, 1).getDay();
  const daysInMonth = new Date(year, month + 1, 0).getDate();

  const prevMonth = () =>
    setCurrentDate(new Date(year, month - 1, 1));

  const nextMonth = () =>
    setCurrentDate(new Date(year, month + 1, 1));

  const toggleFilter = (key) =>
    setFilters({ ...filters, [key]: !filters[key] });

  const getEvents = (day) => {
    const dateStr = `${year}-${String(month + 1).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
    return EVENTS.filter(
      (e) => e.date === dateStr && filters[e.type]
    );
  };

  return (
    <div className="calendar-wrapper">
      {/* FILTER SIDEBAR */}
      <div className="calendar-filters">
        <h3>Filters</h3>

        <label>
          <input
            type="checkbox"
            checked={filters.holiday}
            onChange={() => toggleFilter("holiday")}
          />
          Holidays (Green)
        </label>

        <label>
          <input
            type="checkbox"
            checked={filters.leave}
            onChange={() => toggleFilter("leave")}
          />
          Leaves (Yellow)
        </label>

        <label>
          <input
            type="checkbox"
            checked={filters.birthday}
            onChange={() => toggleFilter("birthday")}
          />
          Birthdays (Blue)
        </label>
      </div>

      {/* CALENDAR */}
      <div className="calendar-container">
        <div className="calendar-header">
          <button onClick={() => setView("month")} className="btn black">
            Month
          </button>

          <div className="month-nav">
            <button onClick={prevMonth} className="btn green">Prev</button>
            <strong>
              {currentDate.toLocaleString("default", {
                month: "long",
                year: "numeric",
              })}
            </strong>
            <button onClick={nextMonth} className="btn green">Next</button>
          </div>

          <button onClick={() => setView("week")} className="btn green">
            Week
          </button>
        </div>

        {/* DAYS HEADER */}
        <div className="days-row">
          {WEEK_DAYS.map((d) => (
            <div key={d}>{d}</div>
          ))}
        </div>

        {/* GRID */}
        <div className="calendar-grid">
          {Array(firstDay).fill(null).map((_, i) => (
            <div key={`empty-${i}`} className="cell empty" />
          ))}

          {Array(daysInMonth).fill(null).map((_, i) => {
            const day = i + 1;
            const events = getEvents(day);

            return (
              <div key={day} className="cell">
                <span className="date">{day}</span>

                {events.map((e, idx) => (
                  <div key={idx} className={`event ${e.type}`}>
                    {e.label}
                  </div>
                ))}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}
